import { GeneratedFile }
  from './types.js';

const EVAL_REQUEST_TYPE =
  'asljs-app-builder:eval-request';

const EVAL_RESPONSE_TYPE =
  'asljs-app-builder:eval-response';

const DIAGNOSTICS_REQUEST_TYPE =
  'asljs-app-builder:diagnostics-request';

const DIAGNOSTICS_RESPONSE_TYPE =
  'asljs-app-builder:diagnostics-response';

export type RuntimeDiagnostics = {
  logs: Array<
    {
      timestamp: number;
      level: string;
      message: string;
    }
  >;
  errors: Array<
    {
      timestamp: number;
      message: string;
    }
  >;
};

type PreviewRenderOptions = {
  hostOpenAiApiKey?: string;
};

const EVAL_BRIDGE_SCRIPT =
  `<script>
(() => {
  const REQUEST = '${EVAL_REQUEST_TYPE}';
  const RESPONSE = '${EVAL_RESPONSE_TYPE}';
  const DIAG_REQUEST = '${DIAGNOSTICS_REQUEST_TYPE}';
  const DIAG_RESPONSE = '${DIAGNOSTICS_RESPONSE_TYPE}';
  const DIAG_KEY = '__asljs_app_builder_diagnostics';
  const MAX_ENTRIES = 250;

  const diagnostics =
    window[DIAG_KEY]
    ?? { logs: [], errors: [] };

  window[DIAG_KEY] = diagnostics;

  const toText = (value) => {
    if (value instanceof Error) {
      const stack = typeof value.stack === 'string' && value.stack !== ''
        ? '\\n' + value.stack
        : '';
      return value.name + ': ' + value.message + stack;
    }

    if (typeof value === 'string') {
      return value;
    }

    if (typeof value === 'number' || typeof value === 'boolean' || value === null || value === undefined) {
      return String(value);
    }

    if (typeof value === 'object') {
      const maybeMessage = typeof value.message === 'string'
        ? value.message
        : null;

      const maybeName = typeof value.name === 'string'
        ? value.name
        : null;

      const maybeStack = typeof value.stack === 'string'
        ? value.stack
        : null;

      if (maybeMessage !== null) {
        const prefix = maybeName !== null
          ? maybeName + ': '
          : '';

        return maybeStack !== null && maybeStack !== ''
          ? prefix + maybeMessage + '\\n' + maybeStack
          : prefix + maybeMessage;
      }
    }

    try {
      return JSON.stringify(value);
    } catch {
      return String(value);
    }
  };

  const append = (list, entry) => {
    list.push(entry);

    if (list.length > MAX_ENTRIES) {
      list.splice(0, list.length - MAX_ENTRIES);
    }
  };

  const addLog = (level, args) => {
    append(
      diagnostics.logs,
      {
        timestamp: Date.now(),
        level,
        message: args.map(toText).join(' '),
      },
    );
  };

  const addError = (message) => {
    append(
      diagnostics.errors,
      {
        timestamp: Date.now(),
        message,
      },
    );
  };

  if (!window.__asljs_app_builder_console_hooked__) {
    window.__asljs_app_builder_console_hooked__ = true;

    const methods = ['log', 'info', 'warn', 'error', 'debug'];

    for (const method of methods) {
      const original = console[method].bind(console);

      console[method] = (...args) => {
        addLog(method, args);

        if (method === 'error') {
          addError(args.map(toText).join(' '));
        }

        original(...args);
      };
    }

    window.addEventListener('error', event => {
      const source = event.filename
        ? ' (' + event.filename + ':' + event.lineno + ':' + event.colno + ')'
        : '';

      const detail = event.error !== undefined
        ? toText(event.error)
        : event.message;

      addError(
        detail && detail !== ''
          ? detail + source
          : 'Unknown runtime error' + source,
      );
    });

    window.addEventListener('unhandledrejection', event => {
      addError('Unhandled rejection: ' + toText(event.reason));
    });
  }

  window.addEventListener('message', async event => {
    const data = event.data;

    if (!data || typeof data.type !== 'string') {
      return;
    }

    if (data.type === DIAG_REQUEST) {
      if (typeof data.id !== 'string') {
        return;
      }

      event.source?.postMessage(
        {
          type: DIAG_RESPONSE,
          id: data.id,
          ok: true,
          diagnostics,
        },
        '*',
      );
      return;
    }

    if (data.type !== REQUEST) {
      return;
    }

    if (typeof data.id !== 'string' || typeof data.code !== 'string') {
      return;
    }

    try {
      const result = (0, eval)(data.code);
      const value = await Promise.resolve(result);

      event.source?.postMessage(
        {
          type: RESPONSE,
          id: data.id,
          ok: true,
          value,
        },
        '*',
      );
    } catch (error) {
      event.source?.postMessage(
        {
          type: RESPONSE,
          id: data.id,
          ok: false,
          error: error instanceof Error
            ? error.message
            : String(error),
        },
        '*',
      );
    }
  });
})();
</script>`;

export function renderPreview(
    frame: HTMLIFrameElement,
    files: GeneratedFile[],
    options?: PreviewRenderOptions
  ): void
{
  if (files.length === 0) {
    frame.removeAttribute('srcdoc');
    frame.src = 'about:blank';
    return;
  }

  const htmlFile =
    files.find(
      file => file.name === 'index.html')
    ?? files.find(
      file => file.name.endsWith('.html'))
    ?? null;

  if (htmlFile === null) {
    frame.removeAttribute('srcdoc');
    frame.src = 'about:blank';
    return;
  }

  let html =
    htmlFile.content;

  const assetUrls =
    createVirtualAssetUrlMap(files);

  const cssFile =
    files.find(
      file => file.name === 'style.css')
    ?? files.find(
      file => file.name.endsWith('.css'))
    ?? null;

  const resolvedCssContent =
    cssFile === null
    ? null
    : replaceCssAssetUrls(
      cssFile.content,
      cssFile.name,
      assetUrls);

  if (cssFile !== null) {
    html = html.replace(
      /<link[^>]+href=["']style\.css["'][^>]*>/gi,
      `<style>${resolvedCssContent}</style>`);

    html = html.replace(
      /<link[^>]+href=["']([^"']+\.css)["'][^>]*>/gi,
      `<style>${resolvedCssContent}</style>`);
  }

  for (const file of files) {
    if (!file.name.endsWith('.js')) {
      continue;
    }

    const escapedName =
      file.name.replace(
        /[.*+?^${}()|[\]\\]/g,
        '\\$&');

    html = html.replace(
      new RegExp(
        `(<script[^>]*?)\\s+src=["']${escapedName}["']([^>]*)><\\/script>`,
        'gi'
      ),
      (
        _match,
        beforeAttrs,
        afterAttrs
      ) =>
      {
        const attrs =
          `${String(beforeAttrs)} ${String(afterAttrs)}`;

        const isModule =
          /type=["']module["']/i.test(attrs);

        return isModule
          ? `<script type="module">${file.content}</script>`
          : `<script>${file.content}</script>`;
      });
  }

  html = replaceHtmlAssetReferences(
    html,
    htmlFile.name,
    assetUrls);

  html = injectPackageImportMap(
    html,
    files);

  html = injectHostContext(
    html,
    options);

  html = injectEvalBridge(html);
  frame.srcdoc = html;
}

export async function evaluateInPreview(
    frame: HTMLIFrameElement,
    code: string
  ): Promise<unknown>
{
  const payload =
    await requestPreviewPayload(
      frame,
      EVAL_REQUEST_TYPE,
      {
      code
    },
      EVAL_RESPONSE_TYPE);

  if (payload.ok === true) {
    return payload.value;
  }

  throw new Error(
    typeof payload.error === 'string'
      ? payload.error
      : 'Unknown preview evaluation error.'
  );
}

export async function getPreviewDiagnostics(
    frame: HTMLIFrameElement
  ): Promise<RuntimeDiagnostics>
{
  const payload =
    await requestPreviewPayload(
      frame,
      DIAGNOSTICS_REQUEST_TYPE,
      {},
      DIAGNOSTICS_RESPONSE_TYPE);

  if (payload.ok !== true) {
    throw new Error(
      typeof payload.error === 'string'
        ? payload.error
        : 'Failed to read preview diagnostics.'
    );
  }

  const diagnostics =
    payload.diagnostics as RuntimeDiagnostics | undefined;

  return diagnostics
    ?? { logs: [], errors: [] };
}

async function requestPreviewPayload(
    frame: HTMLIFrameElement,
    requestType: string,
    requestBody: Record<string, unknown>,
    responseType: string
  ): Promise<Record<string, unknown>>
{
  const frameWindow =
    frame.contentWindow;

  if (frameWindow === null) {
    throw new Error('Preview frame is not available.');
  }

  const requestId =
    crypto.randomUUID();

  return new Promise<Record<string, unknown>>((resolve, reject) =>
  {
    const timeoutId =
      window.setTimeout(
        () =>
      {
        cleanup();

        reject(
          new Error('Timed out waiting for app evaluation result.'));
      },
        5000);

    const onMessage =
      (event: MessageEvent): void =>
    {
      if (event.source !== frameWindow) {
        return;
      }

      const payload =
        event.data as Record<string, unknown>;

      if (
        payload.type !== responseType
        || payload.id !== requestId
      ) {
        return;
      }

      cleanup();
      resolve(payload);
    };

    function cleanup(
      ): void
    {
      window.clearTimeout(timeoutId);

      window.removeEventListener(
        'message',
        onMessage);
    }

    window.addEventListener(
      'message',
      onMessage);

    frameWindow.postMessage(
      {
        type: requestType,
        id: requestId,
        ...requestBody
      },
      '*');
  });
}

function injectEvalBridge(
    html: string
  ): string
{
  if (
    html.includes(
      EVAL_REQUEST_TYPE)
  ) {
    return html;
  }

  if (html.includes('</body>')) {
    return html.replace(
      '</body>',
      `${EVAL_BRIDGE_SCRIPT}</body>`);
  }

  return `${html}\n${EVAL_BRIDGE_SCRIPT}`;
}

function injectPackageImportMap(
    html: string,
    files: GeneratedFile[]
  ): string
{
  if (/type=["']importmap["']/i.test(html)) {
    return html;
  }

  const packageFile =
    files.find(
      file => file.name === 'package.json')
    ?? null;

  const versions =
    readImportMapVersions(
      packageFile?.content);

  const imports =
    Object.fromEntries(
      versions.map(
        ([name, version]) => [
        name,
        `https://esm.sh/${name}@${version}?bundle`
      ]));

  if (Object.keys(imports).length === 0) {
    return html;
  }

  const importMap =
    `<script type="importmap">${
    JSON.stringify(
      { imports })
  }</script>`;

  if (/<head[^>]*>/i.test(html)) {
    return html.replace(
      /<head[^>]*>/i,
      match => `${match}\n${importMap}`);
  }

  return `${importMap}\n${html}`;
}

function readImportMapVersions(
    packageJsonContent: string | undefined
  ): Array<[string, string]>
{
  if (packageJsonContent === undefined) {
    return defaultImportMapPackages();
  }

  try {
    const parsed =
      JSON.parse(
        packageJsonContent) as {
      dependencies?: Record<string, string>;
      devDependencies?: Record<string, string>;
    };

    const source =
      {
      ...(parsed.dependencies ?? {}),
      ...(parsed.devDependencies ?? {})
    };

    const names =
      [
      'asljs-eventful',
      'asljs-observable',
      'asljs-data-binding',
      'asljs-components',
      'asljs-dali',
      'openai'
    ];

    const versions =
      names.map(
        (name): [string, string] => [
        name,
        normalizeNpmVersion(
          source[name])
      ]);

    return versions;
  } catch {
    return defaultImportMapPackages();
  }
}

function normalizeNpmVersion(
    value: string | undefined
  ): string
{
  if (typeof value !== 'string' || value.trim() === '') {
    return 'latest';
  }

  const cleaned =
    value.trim().replace(
      /^[~^<>=\s]+/,
      '');

  return cleaned === ''
    ? 'latest'
    : cleaned;
}

function defaultImportMapPackages(
  ): Array<[string, string]>
{
  return [
    ['asljs-eventful', 'latest'],
    ['asljs-observable', 'latest'],
    ['asljs-data-binding', 'latest'],
    ['asljs-components', 'latest'],
    ['asljs-dali', 'latest'],
    ['openai', 'latest']
  ];
}

function injectHostContext(
    html: string,
    options: PreviewRenderOptions | undefined
  ): string
{
  if (
    html.includes(
      '__ASLJS_APP_BUILDER_HOST__')
  ) {
    return html;
  }

  const script =
    `<script>window.__ASLJS_APP_BUILDER_HOST__ = ${
    JSON.stringify(
      {
        openAiApiKey: options?.hostOpenAiApiKey === undefined
            || options.hostOpenAiApiKey.trim() === ''
          ? null
          : options.hostOpenAiApiKey
      })
  };</script>`;

  if (html.includes('</head>')) {
    return html.replace(
      '</head>',
      `${script}</head>`);
  }

  if (html.includes('<body')) {
    return html.replace(
      /<body[^>]*>/i,
      match => `${match}\n${script}`);
  }

  return `${script}\n${html}`;
}

function createVirtualAssetUrlMap(
    files: GeneratedFile[]
  ): Map<string, string>
{
  const assetUrls = new Map<string, string>();

  for (const file of files) {
    const assetUrl =
      readEmbeddableAssetUrl(
        file.content);

    if (assetUrl === null) {
      continue;
    }

    assetUrls.set(
      normalizeVirtualPath(
        file.name),
      assetUrl);
  }

  return assetUrls;
}

function readEmbeddableAssetUrl(
    content: string
  ): string | null
{
  const trimmed =
    content.trim();

  return /^data:[^,]+,.+/i.test(trimmed)
    ? trimmed
    : null;
}

function replaceHtmlAssetReferences(
    html: string,
    htmlPath: string,
    assetUrls: Map<string, string>
  ): string
{
  return html.replace(
    /\b(src|href|poster)=(["'])([^"']+)\2/gi,
    (match, attributeName, quote, originalPath) =>
    {
      const resolved =
        resolveVirtualAssetReference(
          htmlPath,
          String(originalPath),
          assetUrls);

      return resolved === null
        ? match
        : `${String(attributeName)}=${String(quote)}${resolved}${
          String(quote)
        }`;
    });
}

function replaceCssAssetUrls(
    css: string,
    cssPath: string,
    assetUrls: Map<string, string>
  ): string
{
  return css.replace(
    /url\(\s*(["']?)([^"')]+)\1\s*\)/gi,
    (match, quote, originalPath) =>
    {
      const resolved =
        resolveVirtualAssetReference(
          cssPath,
          String(originalPath),
          assetUrls);

      return resolved === null
        ? match
        : `url(${String(quote)}${resolved}${String(quote)})`;
    });
}

function resolveVirtualAssetReference(
    sourcePath: string,
    referencePath: string,
    assetUrls: Map<string, string>
  ): string | null
{
  const trimmed =
    referencePath.trim();

  if (
    trimmed === ''
    || trimmed.startsWith('#')
    || /^[a-z]+:/i.test(trimmed)
    || trimmed.startsWith('//')
  ) {
    return null;
  }

  const withoutHash =
    trimmed.split(
      '#',
      1)[0] ?? trimmed;

  const withoutQuery =
    withoutHash.split(
      '?',
      1)[0] ?? withoutHash;

  const resolvedPath =
    normalizeVirtualPath(
      joinVirtualPath(
        parentVirtualDirectory(sourcePath),
        withoutQuery));

  return assetUrls.get(resolvedPath) ?? null;
}

function parentVirtualDirectory(
    path: string
  ): string
{
  const segments =
    normalizeVirtualPath(path).split('/');

  segments.pop();
  return segments.join('/');
}

function joinVirtualPath(
    basePath: string,
    nextPath: string
  ): string
{
  if (nextPath.startsWith('/')) {
    return nextPath;
  }

  return basePath === ''
    ? nextPath
    : `${basePath}/${nextPath}`;
}

function normalizeVirtualPath(
    path: string
  ): string
{
  const parts =
    path
    .replace(
      /\\/g,
      '/')
    .split('/');

  const normalized: string[] = [];

  for (const part of parts) {
    if (part === '' || part === '.') {
      continue;
    }

    if (part === '..') {
      normalized.pop();
      continue;
    }

    normalized.push(part);
  }

  return normalized.join('/');
}
